class Solution {
public:
    bool makeStringsEqual(string s, string target) {
        int n = s.size();
        int count1s = 0;
        for (int i = 0; i < n; i++) {
            if (s[i] == '1') count1s++;
        }
        int count1t = 0;
        for (int i = 0; i < n; i++) {
            if (target[i] == '1') count1t++;
        }
        if (count1s == 0 && count1t == 0) return true;
        if (count1s == 0 || count1t == 0) return false;
        return true;
    }
};
